import hashlib


def hash_file(filepath, algorithm="sha256", chunk_size=8192):
    """
    Create a cryptographic hash of a file for integrity checking.

    Args:
        filepath: Path to the file to hash.
        algorithm: Hash algorithm to use (default: sha256).
        chunk_size: Size of chunks to read at a time (default: 8192 bytes).

    Returns:
        Hex digest string of the file's hash.

    Raises:
        ValueError: If an unsupported or insecure algorithm is specified.
        FileNotFoundError: If the file does not exist.
        IOError: If the file cannot be read.
    """
    # Block weak/insecure hash algorithms
    insecure_algorithms = {"md5", "sha1", "md4", "md2"}
    if algorithm.lower() in insecure_algorithms:
        raise ValueError(
            f"Algorithm '{algorithm}' is considered cryptographically weak. "
            f"Use 'sha256', 'sha384', 'sha512', or 'sha3_256' instead."
        )

    # Validate that the algorithm is available
    if algorithm.lower() not in hashlib.algorithms_available:
        raise ValueError(
            f"Algorithm '{algorithm}' is not available. "
            f"Available algorithms: {sorted(hashlib.algorithms_available)}"
        )

    hasher = hashlib.new(algorithm)

    with open(filepath, "rb") as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            hasher.update(chunk)

    return hasher.hexdigest()


def verify_file(filepath, expected_hash, algorithm="sha256"):
    """
    Verify a file's integrity by comparing its hash to an expected value.

    Uses constant-time comparison to prevent timing attacks.

    Args:
        filepath: Path to the file to verify.
        expected_hash: The expected hex digest string.
        algorithm: Hash algorithm to use (default: sha256).

    Returns:
        True if the file's hash matches the expected hash, False otherwise.
    """
    import hmac

    actual_hash = hash_file(filepath, algorithm=algorithm)
    # Use constant-time comparison to prevent timing side-channel attacks
    return hmac.compare_digest(actual_hash, expected_hash.lower())


